#!/usr/bin/env python3
import json

def difficulty(n):
    if n <= 8: return "easy"
    if n <= 18: return "medium"
    return "hard"

all_problems = []

# Helper to add problems
def add_problems(year, source_link, problems_data):
    for i, (prob, choices, ans, topic) in enumerate(problems_data):
        num = i + 1
        all_problems.append({
            "contest": "AMC 10A",
            "year": year,
            "number": num,
            "topic": topic,
            "difficulty": difficulty(num),
            "problem": prob,
            "choices": choices,
            "correct_answer": ans,
            "correct_value": choices[ord(ans) - 65],
            "solution": "See AoPS wiki for detailed solution.",
            "track": "math",
            "source_link": source_link
        })

